const candidates = $input.all().map(item => item.json);

const rawUserState = $('Read UserState For AI').first().json;

// Функція безпечно дістає поле навіть якщо в назві колонки є зайві пробіли
function getField(obj, fieldName) {
  const exactValue = obj[fieldName];

  if (exactValue !== undefined && exactValue !== null && exactValue !== '') {
    return exactValue;
  }

  const foundKey = Object.keys(obj).find(key => key.trim() === fieldName);

  if (foundKey) {
    return obj[foundKey];
  }

  return '';
}

const businessProblem = getField(rawUserState, 'business_problem');
const criteria = getField(rawUserState, 'criteria');
const vacancyText = getField(rawUserState, 'vacancy_text');

const candidateCards = candidates.map(c => {
  return `
Candidate ID: ${c.candidate_id}
Full name: ${c.full_name}
Experience level: ${c.experience_level}
Tier: ${c.tier}
Short summary: ${c.short_summary}
Key skills: ${c.key_skills}
Match notes: ${c.match_notes}
Risk notes: ${c.risk_notes}
Status: ${c.status}
`;
}).join('\n---\n');

const prompt = `
You are an AI recruitment assistant for an MVP called FlowScope AI.

Your task is to analyze prepared candidate cards against the user's hiring request.

Important context:
- The user does not upload CVs in Telegram.
- CVs were already received and pre-processed.
- You are working with structured candidate cards from the Candidates database.
- Be practical, concise, and explain your reasoning clearly.

Important evaluation rules:
- Do not force a shortlist if candidates do not match the vacancy.
- If the candidate database does not contain suitable candidates for the vacancy, say so clearly.
- Match candidates primarily against the user's vacancy description and criteria, not against their original pre-assigned tier.
- A high technical tier does not automatically mean a good match for a non-technical vacancy.
- If a candidate profile is irrelevant to the vacancy, mark decision as reject even if the candidate is generally strong.
- If the vacancy requires sales, customer communication, CRM, or account management experience, do not treat technical Python/backend experience as a substitute for sales experience.
- Only mark candidate as invite if the candidate card explicitly contains relevant sales, customer-facing, CRM, or client communication experience.
- If no candidate clearly matches, say that there is no strong match in the current database.

User business problem:
${businessProblem}

User selection criteria:
${criteria}

Vacancy description:
${vacancyText}

Candidate cards:
${candidateCards}

Analyze all candidates and return the result in Ukrainian.

Output format:

1. Shortlist:
- candidate_id
- full_name
- score from 0 to 100
- decision: invite / maybe / reject
- short reason

2. Best candidates:
Explain who should be invited first and why.

3. Rejected candidates:
Explain who should not be considered for this vacancy and why.

4. Risks:
Mention important risks such as overqualification, missing must-have skills, weak experience, irrelevant profile, or incomplete contact data.

5. Screening questions:
Give 3 screening questions for the strongest candidate.
`;

return [
  {
    json: {
      user_id: getField(rawUserState, 'user_id'),
      chat_id: $('Prepare Message Data').first().json.chat_id || $('Prepare Message Data').first().json.user_id,
      business_problem: businessProblem,
      criteria: criteria,
      vacancy_text: vacancyText,
      candidates_count: candidates.length,
      prompt
    }
  }
];

