const data = $input.first().json;

let aiResult = '';

// Варіант 1: якщо OpenAI повернув масив message-об'єктів
if (Array.isArray(data) && data[0]?.content?.[0]?.text) {
  aiResult = data[0].content[0].text;

// Варіант 2: якщо відповідь лежить у полі output як масив
} else if (Array.isArray(data.output) && data.output[0]?.content?.[0]?.text) {
  aiResult = data.output[0].content[0].text;

// Варіант 3: якщо відповідь лежить у content[0].text
} else if (data.content?.[0]?.text) {
  aiResult = data.content[0].text;

// Варіант 4: якщо відповідь лежить у message.content
} else if (data.message?.content) {
  aiResult = data.message.content;

// Варіант 5: якщо відповідь лежить у text
} else if (data.text) {
  aiResult = data.text;

// Варіант 6: класичний choices
} else if (data.choices?.[0]?.message?.content) {
  aiResult = data.choices[0].message.content;

// fallback
} else {
  aiResult = JSON.stringify(data, null, 2);
}

return [
  {
    json: {
      user_id: $('Prepare AI Prompt').first().json.user_id,
      chat_id: $('Prepare AI Prompt').first().json.chat_id,
      username: $('Read UserState For AI').first().json.username,
      business_problem: $('Prepare AI Prompt').first().json.business_problem,
      criteria: $('Prepare AI Prompt').first().json.criteria,
      vacancy_text: $('Prepare AI Prompt').first().json.vacancy_text,
      candidates_count: $('Prepare AI Prompt').first().json.candidates_count,
      ai_result: aiResult,
      status: 'completed',
      notes: 'MVP analysis completed',
      timestamp: new Date().toISOString()
    }
  }
];
